$(document).ready(function () {

    var baseUrl = window.location.origin;
    let retrive_data = baseUrl + '/ca_report_purchase_ajax';

    let grandTotal = 0;

    var table = $('#ca-report-purchase').DataTable({
        processing: true,
        serverSide: true,
        destroy: true,
        dom: 'Bfrtip',

        buttons: [

            // ================== ✅ EXCEL ==================
            {
                extend: 'excelHtml5',
                text: 'Export to Excel',
                filename: 'CA_Purchase_Report',

                action: function (e, dt, button, config) {
                    var self = this;

                    dt.one('preXhr', function (e, s, data) {
                        data.length = -1;
                    });

                    dt.one('draw', function () {
                        $.fn.dataTable.ext.buttons.excelHtml5.action.call(self, e, dt, button, config);

                        dt.one('preXhr', function (e, s, data) {
                            data.length = 10;
                        });

                        setTimeout(function () {
                            dt.ajax.reload();
                        }, 100);
                    });

                    dt.ajax.reload();
                },

                customize: function (xlsx) {

                    var sheet = xlsx.xl.worksheets['sheet1.xml'];
                    var sheetData = $('sheetData', sheet);

                    // ✅ Get values
                    var from_date = $('.from_date').val() || '';
                    var to_date = $('.to_date').val() || '';
                    var financial_year = $('.financial_year option:selected').text() || '';

                    // ✅ Title
                    $('c[r=A1] t', sheet).text('CA Purchase Report');

                    // ✅ Last row
                    var lastRow = $('sheetData row', sheet).length + 1;

                    // ✅ Grand Total
                    sheetData.append(`
                        <row r="${lastRow}">
                            <c t="inlineStr" s="2" r="A${lastRow}">
                                <is><t>Grand Total</t></is>
                            </c>
                            <c t="n" s="2" r="C${lastRow}">
                                <v>${parseFloat(grandTotal || 0).toFixed(2)}</v>
                            </c>
                        </row>
                    `);

                    // ================== ✅ FILTER (SEPARATE ROWS) ==================

                    var row1 = lastRow + 2;
                    var row2 = lastRow + 3;
                    var row3 = lastRow + 4;

                    // From
                    sheetData.append(`
                        <row r="${row1}">
                            <c t="inlineStr" s="2" r="A${row1}">
                                <is><t>From : ${from_date}</t></is>
                            </c>
                        </row>
                    `);

                    // To
                    sheetData.append(`
                        <row r="${row2}">
                            <c t="inlineStr" s="2" r="A${row2}">
                                <is><t>To : ${to_date}</t></is>
                            </c>
                        </row>
                    `);

                    // Financial Year
                    sheetData.append(`
                        <row r="${row3}">
                            <c t="inlineStr" s="2" r="A${row3}">
                                <is><t>Financial Year : ${financial_year}</t></is>
                            </c>
                        </row>
                    `);

                    // ✅ Merge full width (A to C)
                    if (!$('mergeCells', sheet).length) {
                        $('worksheet', sheet).append('<mergeCells></mergeCells>');
                    }

                    var mergeCells = $('mergeCells', sheet);

                    mergeCells.append(`<mergeCell ref="A${row1}:C${row1}"/>`);
                    mergeCells.append(`<mergeCell ref="A${row2}:C${row2}"/>`);
                    mergeCells.append(`<mergeCell ref="A${row3}:C${row3}"/>`);
                }
            },

            // ================== ✅ PDF ==================
            {
                extend: 'pdfHtml5',
                text: 'Export to PDF',
                filename: 'CA_Purchase_Report',

                action: function (e, dt, button, config) {
                    var self = this;

                    dt.one('preXhr', function (e, s, data) {
                        data.length = -1;
                    });

                    dt.one('draw', function () {

                        $.fn.dataTable.ext.buttons.pdfHtml5.action.call(self, e, dt, button, config);

                        dt.one('preXhr', function (e, s, data) {
                            data.length = 10;
                        });

                        setTimeout(function () {
                            dt.ajax.reload();
                        }, 100);
                    });

                    dt.ajax.reload();
                },

                customize: function (doc) {

                    var from_date = $('.from_date').val() || '';
                    var to_date = $('.to_date').val() || '';
                    var financial_year = $('.financial_year option:selected').text() || '';

                    // ✅ FILTER (MULTI LINE)
                    var filterText = [
                        { text: 'From : ' + from_date },
                        { text: 'To : ' + to_date },
                        { text: 'Financial Year : ' + financial_year }
                    ];

                    // ✅ Title
                    doc.content.splice(0, 0, {
                        text: 'CA Purchase Report',
                        fontSize: 14,
                        bold: true,
                        alignment: 'center',
                        margin: [0, 0, 0, 10]
                    });

                    // ✅ Table styling
                    var table = doc.content.find(item => item.table);

                    if (table) {
                        table.table.widths = ['auto', '*', 'auto'];
                        table.margin = [60, 0, 60, 0];
                    }

                    // ✅ Grand Total
                    doc.content.push({
                        text: 'Grand Total: ₹ ' + parseFloat(grandTotal || 0).toFixed(2),
                        margin: [0, 10, 0, 5],
                        bold: true,
                        alignment: 'center'
                    });

                    // ✅ FILTER AT END
                    doc.content.push({
                        stack: filterText,
                        margin: [0, 5, 0, 0],
                        alignment: 'left'
                    });
                }
            }
        ],

        ajax: {
            url: retrive_data,
            data: function (d) {
                d.from_date = $('.from_date').val();
                d.to_date = $('.to_date').val();
                d.financial_year = $('.financial_year').val();
                d.category = $('.category').val();
                d.subcategory = $('.subcategory').val();
            },
            dataSrc: function (json) {
                grandTotal = json.grand_total || 0;
                return json.data;
            }
        },

        columns: [
            {
                data: null,
                render: function (data, type, row, meta) {
                    return meta.row + 1;
                }
            },
            { data: "subcategory_name" },
            { data: "total_amount" }
        ],

        footerCallback: function () {
            var api = this.api();
            var json = api.ajax.json();

            if (json && json.grand_total) {
                $(api.column(2).footer())
                    .html('₹ ' + parseFloat(json.grand_total).toFixed(2));
            }
        }
    });

    // Reload on filter
    $('.submit_purchase_report').click(function () {
         var from_date = $('.from_date').val();
    var to_date = $('.to_date').val();
    var financial_year = $('.financial_year option:selected').text();

    if (!from_date || !to_date || !financial_year) {
        alert("Please select all fields");
        return;
    }

    // ✅ Split financial year
    var yearParts = financial_year.split('-');

    var startYear = yearParts[0];
    var endYear   = yearParts[1];

    // ✅ Financial Year Range
    var fy_start = new Date(startYear + '-04-01');
    var fy_end   = new Date(endYear + '-03-31');

    var from = new Date(from_date);
    var to   = new Date(to_date);

    // ✅ VALIDATION
    if (from < fy_start || to > fy_end) {
        alert("Select date within the financial year");
        return;
    }
      var from_date = $('.from_date').val();
    var to_date = $('.to_date').val();
    var financial_year = $('.financial_year option:selected').text();

    if (!from_date || !to_date || !financial_year) {
        alert("Please select all fields");
        return;
    }

    // ✅ Split financial year
    var yearParts = financial_year.split('-');

    var startYear = yearParts[0];
    var endYear   = yearParts[1];

    // ✅ Financial Year Range
    var fy_start = new Date(startYear + '-04-01');
    var fy_end   = new Date(endYear + '-03-31');

    var from = new Date(from_date);
    var to   = new Date(to_date);

    // ✅ VALIDATION
    if (from < fy_start || to > fy_end) {
        alert("Select date within the financial year");
        return;
    }

    // From Greater the To Date Validation
    if (from > to) {
    alert("From date should not be greater than To date");
    return;
    }
        table.ajax.reload();
    });

});